import api from '@/api/axios'

export async function getTasks(params?: Record<string, any>) {
  const response = await api.get('/tasks', { params })
  return response.data
}

export async function getTask(id: number) {
  const response = await api.get(`/tasks/${id}`)
  return response.data
}

export async function createTask(data: Record<string, any>) {
  const response = await api.post('/tasks', data)
  return response.data
}

export async function updateTask(id: number, data: Record<string, any>) {
  const response = await api.put(`/tasks/${id}`, data)
  return response.data
}

export async function deleteTask(id: number) {
  await api.delete(`/tasks/${id}`)
}

export async function updateStatus(id: number, status: string) {
  const response = await api.patch(`/tasks/${id}/status`, { status })
  return response.data
}

export async function getTransitions(id: number) {
  const response = await api.get(`/tasks/${id}/transitions`)
  return response.data
}

import { defineStore } from 'pinia'
import { getTasks as apiGetTasks, createTask as apiCreateTask } from '@/api/tasks'

export const useTaskStore = defineStore('task', {
  state: () => ({
    tasks: [] as any[],
    page: 0,
    size: 20,
    totalElements: 0,
    totalPages: 0,
    keyword: '',
    priorityFilter: '',
    statusFilter: '',
    loading: false,
    error: null as string | null,
  }),

  actions: {
    async fetchTasks() {
      this.loading = true
      this.error = null
      try {
        const data = await apiGetTasks({
          page: this.page,
          size: this.size,
          keyword: this.keyword,
          priority: this.priorityFilter,
          status: this.statusFilter,
        })
        this.tasks = data.content
        this.page = data.page
        this.totalElements = data.totalElements
        this.totalPages = data.totalPages
      } catch (e: any) {
        this.error = e.message
      } finally {
        this.loading = false
      }
    },

    setKeyword(kw: string) {
      this.keyword = kw
      this.page = 0
    },

    setPriorityFilter(p: string) {
      this.priorityFilter = p
      this.page = 0
    },

    setStatusFilter(s: string) {
      this.statusFilter = s
      this.page = 0
    },

    setPage(p: number) {
      this.page = p
    },

    async createTask(data: Record<string, any>) {
      await apiCreateTask(data)
      await this.fetchTasks()
    },
  },
})

import { createRouter, createWebHistory } from 'vue-router'
import { defineComponent, h } from 'vue'

const PlaceholderComponent = defineComponent({
  render() {
    return h('div', 'Loading...')
  },
})

const router = createRouter({
  history: createWebHistory(),
  routes: [
    {
      path: '/',
      name: 'home',
      component: () => import('../views/HomeView.vue'),
    },
    {
      path: '/tasks',
      name: 'task-list',
      component: PlaceholderComponent,
    },
    {
      path: '/tasks/:id',
      name: 'task-detail',
      component: PlaceholderComponent,
    },
  ],
})

export default router

