// We import the axios instance that should be created at @/api/axios
// This will fail until the module is implemented
import api from '@/api/axios'

describe('Axios Instance', () => {
  beforeEach(() => {
    localStorage.clear()
  })

  afterEach(() => {
    localStorage.clear()
  })

  it('should have baseURL set to /api', () => {
    expect(api.defaults.baseURL).toBe('/api')
  })

  it('should attach Authorization header when token exists in localStorage', async () => {
    localStorage.setItem('token', 'test-jwt-token')

    // Use interceptor manually by creating a mock config
    const interceptor = (api.interceptors.request as any).handlers[0]
    expect(interceptor).toBeDefined()

    const config = { headers: {} } as any
    const result = interceptor.fulfilled(config)
    expect(result.headers.Authorization).toBe('Bearer test-jwt-token')
  })

  it('should NOT attach Authorization header when no token in localStorage', async () => {
    const interceptor = (api.interceptors.request as any).handlers[0]
    expect(interceptor).toBeDefined()

    const config = { headers: {} } as any
    const result = interceptor.fulfilled(config)
    expect(result.headers.Authorization).toBeUndefined()
  })
})

