import api from '@/api/axios'
import {
  getTasks,
  getTask,
  createTask,
  updateTask,
  deleteTask,
  updateStatus,
  getTransitions,
} from '@/api/tasks'

describe('Tasks API', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  describe('getTasks', () => {
    it('should call GET /tasks with query params', async () => {
      const mockPage = {
        data: {
          content: [],
          page: 0,
          size: 20,
          totalElements: 0,
          totalPages: 0,
        },
      }
      vi.mocked(api.get).mockResolvedValue(mockPage)

      const params = { page: 0, size: 20, keyword: 'test', priority: 'HIGH' }
      const result = await getTasks(params)

      expect(api.get).toHaveBeenCalledWith('/tasks', { params })
      expect(result).toEqual(mockPage.data)
    })

    it('should work with no params', async () => {
      const mockPage = {
        data: {
          content: [],
          page: 0,
          size: 20,
          totalElements: 0,
          totalPages: 0,
        },
      }
      vi.mocked(api.get).mockResolvedValue(mockPage)

      await getTasks()
      expect(api.get).toHaveBeenCalledWith('/tasks', { params: undefined })
    })

    it('should return PageResponse structure', async () => {
      const mockData = {
        content: [{ id: 1, title: 'Task 1' }],
        page: 0,
        size: 20,
        totalElements: 1,
        totalPages: 1,
      }
      vi.mocked(api.get).mockResolvedValue({ data: mockData })

      const result = await getTasks({ page: 0, size: 20 })

      expect(result).toHaveProperty('content')
      expect(result).toHaveProperty('page')
      expect(result).toHaveProperty('size')
      expect(result).toHaveProperty('totalElements')
      expect(result).toHaveProperty('totalPages')
    })
  })

  describe('getTask', () => {
    it('should call GET /tasks/:id', async () => {
      const mockTask = { data: { id: 1, title: 'Task 1' } }
      vi.mocked(api.get).mockResolvedValue(mockTask)

      const result = await getTask(1)

      expect(api.get).toHaveBeenCalledWith('/tasks/1')
      expect(result).toEqual(mockTask.data)
    })
  })

  describe('createTask', () => {
    it('should call POST /tasks with task data', async () => {
      const taskData = { title: 'New Task', description: 'Desc', priority: 'HIGH' as const }
      const mockResponse = { data: { id: 1, ...taskData, status: 'TODO' } }
      vi.mocked(api.post).mockResolvedValue(mockResponse)

      const result = await createTask(taskData)

      expect(api.post).toHaveBeenCalledWith('/tasks', taskData)
      expect(result).toEqual(mockResponse.data)
    })
  })

  describe('updateTask', () => {
    it('should call PUT /tasks/:id with updated data', async () => {
      const updateData = { title: 'Updated', description: 'New desc' }
      const mockResponse = { data: { id: 5, ...updateData, status: 'TODO' } }
      vi.mocked(api.put).mockResolvedValue(mockResponse)

      const result = await updateTask(5, updateData)

      expect(api.put).toHaveBeenCalledWith('/tasks/5', updateData)
      expect(result).toEqual(mockResponse.data)
    })
  })

  describe('deleteTask', () => {
    it('should call DELETE /tasks/:id', async () => {
      vi.mocked(api.delete).mockResolvedValue({ status: 204 })

      await deleteTask(3)

      expect(api.delete).toHaveBeenCalledWith('/tasks/3')
    })
  })

  describe('updateStatus', () => {
    it('should call PATCH /tasks/:id/status with new status', async () => {
      const mockResponse = { data: { id: 2, status: 'IN_PROGRESS' } }
      vi.mocked(api.patch).mockResolvedValue(mockResponse)

      const result = await updateStatus(2, 'IN_PROGRESS')

      expect(api.patch).toHaveBeenCalledWith('/tasks/2/status', {
        status: 'IN_PROGRESS',
      })
      expect(result).toEqual(mockResponse.data)
    })
  })

  describe('getTransitions', () => {
    it('should call GET /tasks/:id/transitions', async () => {
      const mockResponse = {
        data: {
          currentStatus: 'TODO',
          availableTransitions: ['IN_PROGRESS'],
        },
      }
      vi.mocked(api.get).mockResolvedValue(mockResponse)

      const result = await getTransitions(7)

      expect(api.get).toHaveBeenCalledWith('/tasks/7/transitions')
      expect(result).toEqual(mockResponse.data)
    })
  })
})

