import { useTaskStore } from '@/stores/taskStore'
import * as tasksApi from '@/api/tasks'

describe('Task Store', () => {
  beforeEach(() => {
    setActivePinia(createPinia())
    vi.clearAllMocks()
  })

  describe('initial state', () => {
    it('should have correct default values', () => {
      const store = useTaskStore()

      expect(store.tasks).toEqual([])
      expect(store.page).toBe(0)
      expect(store.size).toBe(20)
      expect(store.totalElements).toBe(0)
      expect(store.totalPages).toBe(0)
      expect(store.keyword).toBe('')
      expect(store.priorityFilter).toBe('')
      expect(store.statusFilter).toBe('')
      expect(store.loading).toBe(false)
      expect(store.error).toBeNull()
    })
  })

  describe('fetchTasks', () => {
    it('should set loading=true during request and false after', async () => {
      const store = useTaskStore()
      let loadingDuringRequest = false

      vi.mocked(tasksApi.getTasks).mockImplementation(async () => {
        loadingDuringRequest = store.loading
        return {
          content: [],
          page: 0,
          size: 20,
          totalElements: 0,
          totalPages: 0,
        }
      })

      await store.fetchTasks()

      expect(loadingDuringRequest).toBe(true)
      expect(store.loading).toBe(false)
    })

    it('should update tasks and pagination from API response', async () => {
      const store = useTaskStore()
      const mockTasks = [
        { id: 1, title: 'Task 1', status: 'TODO', priority: 'HIGH' },
        { id: 2, title: 'Task 2', status: 'IN_PROGRESS', priority: 'LOW' },
      ]
      vi.mocked(tasksApi.getTasks).mockResolvedValue({
        content: mockTasks,
        page: 0,
        size: 20,
        totalElements: 2,
        totalPages: 1,
      })

      await store.fetchTasks()

      expect(store.tasks).toEqual(mockTasks)
      expect(store.totalElements).toBe(2)
      expect(store.totalPages).toBe(1)
    })

    it('should pass page, size, keyword, priority, status filters to API', async () => {
      const store = useTaskStore()
      store.keyword = 'search'
      store.priorityFilter = 'HIGH'
      store.statusFilter = 'TODO'
      store.page = 2
      store.size = 10

      vi.mocked(tasksApi.getTasks).mockResolvedValue({
        content: [],
        page: 2,
        size: 10,
        totalElements: 0,
        totalPages: 0,
      })

      await store.fetchTasks()

      expect(tasksApi.getTasks).toHaveBeenCalledWith(
        expect.objectContaining({
          page: 2,
          size: 10,
          keyword: 'search',
          priority: 'HIGH',
          status: 'TODO',
        })
      )
    })

    it('should set error on API failure', async () => {
      const store = useTaskStore()
      vi.mocked(tasksApi.getTasks).mockRejectedValue(new Error('Network error'))

      await store.fetchTasks()

      expect(store.error).toBe('Network error')
      expect(store.loading).toBe(false)
    })

    it('should handle empty task list', async () => {
      const store = useTaskStore()
      vi.mocked(tasksApi.getTasks).mockResolvedValue({
        content: [],
        page: 0,
        size: 20,
        totalElements: 0,
        totalPages: 0,
      })

      await store.fetchTasks()

      expect(store.tasks).toEqual([])
      expect(store.totalElements).toBe(0)
      expect(store.totalPages).toBe(0)
    })
  })

  describe('setKeyword', () => {
    it('should set keyword and reset page to 0', () => {
      const store = useTaskStore()
      store.page = 5

      store.setKeyword('new search')

      expect(store.keyword).toBe('new search')
      expect(store.page).toBe(0)
    })
  })

  describe('setPriorityFilter', () => {
    it('should set priority filter and reset page to 0', () => {
      const store = useTaskStore()
      store.page = 3

      store.setPriorityFilter('HIGH')

      expect(store.priorityFilter).toBe('HIGH')
      expect(store.page).toBe(0)
    })
  })

  describe('setStatusFilter', () => {
    it('should set status filter and reset page to 0', () => {
      const store = useTaskStore()
      store.page = 2

      store.setStatusFilter('DONE')

      expect(store.statusFilter).toBe('DONE')
      expect(store.page).toBe(0)
    })
  })

  describe('setPage', () => {
    it('should update the page number', () => {
      const store = useTaskStore()

      store.setPage(4)

      expect(store.page).toBe(4)
    })
  })

  describe('createTask', () => {
    it('should call API createTask and then fetchTasks', async () => {
      const store = useTaskStore()
      const taskData = { title: 'New Task', priority: 'MEDIUM' as const }
      const mockCreated = { id: 10, ...taskData, status: 'TODO' }

      vi.mocked(tasksApi.createTask).mockResolvedValue(mockCreated)
      vi.mocked(tasksApi.getTasks).mockResolvedValue({
        content: [mockCreated],
        page: 0,
        size: 20,
        totalElements: 1,
        totalPages: 1,
      })

      await store.createTask(taskData)

      expect(tasksApi.createTask).toHaveBeenCalledWith(taskData)
      // Should refresh the list after creating
      expect(tasksApi.getTasks).toHaveBeenCalled()
    })
  })
})

import { describe, it, expect } from 'vitest'
import router from '@/router/index'

describe('Router Configuration', () => {
  it('should have /tasks route', () => {
    const tasksRoute = router.getRoutes().find((r) => r.path === '/tasks')
    expect(tasksRoute).toBeDefined()
    expect(tasksRoute!.name).toBe('task-list')
  })

  it('should have /tasks/:id route', () => {
    const taskDetailRoute = router
      .getRoutes()
      .find((r) => r.path === '/tasks/:id')
    expect(taskDetailRoute).toBeDefined()
    expect(taskDetailRoute!.name).toBe('task-detail')
  })

  it('should still have / (home) route', () => {
    const homeRoute = router.getRoutes().find((r) => r.path === '/')
    expect(homeRoute).toBeDefined()
    expect(homeRoute!.name).toBe('home')
  })
})
